"use strict";(self.webpackChunkzhishi=self.webpackChunkzhishi||[]).push([[8169],{9556:(e,r,n)=>{n.r(r),n.d(r,{data:()=>i});const i={key:"v-87d5e67a",path:"/fe/microFE/",title:"微前端",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"为什么不用 iframe",slug:"为什么不用-iframe",children:[]},{level:2,title:"微前端的价值",slug:"微前端的价值",children:[]},{level:2,title:"qiankun 源码分析",slug:"qiankun-源码分析",children:[]}],filePathRelative:"fe/microFE/README.md",git:{updatedTime:1626626739e3,contributors:[{name:"tangxue",email:"11183504@qq.com",commits:1}]}}},585:(e,r,n)=>{n.r(r),n.d(r,{default:()=>g});var i=n(6252);const a=(0,i.Wm)("h1",{id:"微前端",tabindex:"-1"},[(0,i.Wm)("a",{class:"header-anchor",href:"#微前端","aria-hidden":"true"},"#"),(0,i.Uk)(" 微前端")],-1),t={href:"https://tech.antfin.com/community/articles/536",target:"_blank",rel:"noopener noreferrer"},l=(0,i.Uk)("可能是你见过最完善的微前端解决方案"),o={href:"https://juejin.cn/post/6846687602439897101#heading-12",target:"_blank",rel:"noopener noreferrer"},u=(0,i.Uk)("qiankun 的技术实现与选择"),h={href:"https://juejin.cn/post/6844904115999342600",target:"_blank",rel:"noopener noreferrer"},s=(0,i.Uk)("qiankun 源码分析"),m=(0,i.Wm)("h2",{id:"为什么不用-iframe",tabindex:"-1"},[(0,i.Wm)("a",{class:"header-anchor",href:"#为什么不用-iframe","aria-hidden":"true"},"#"),(0,i.Uk)(" 为什么不用 iframe")],-1),p={href:"https://www.yuque.com/kuitos/gky7yw/gesexv",target:"_blank",rel:"noopener noreferrer"},c=(0,i.Uk)("为什么不用 iframe"),d=(0,i.uE)('<p>iframe 最大的特性就是提供了浏览器原生的硬隔离方案，不论是样式隔离、js 隔离这类问题统统都能被完美解决。</p><p>但他的最大问题也在于他的隔离性无法被突破，<strong>导致应用间上下文无法被共享</strong>，随之带来的开发体验、产品体验的问题。</p><p><strong>iframe 导致的问题：</strong></p><ul><li>url 不同步。浏览器刷新 iframe url 状态丢失、后退前进按钮无法使用。</li><li>UI 不同步、DOM 结构不共享。想象一下屏幕右下角 1/4 的 iframe 里来一个带遮罩层的弹框，同时我们要求这个弹框要浏览器居中显示，还要浏览器 resize 时自动居中..</li><li>全局上下文完全隔离，内存变量不共享。iframe 内外系统的通信、数据同步等需求，主应用的 cookie 要透传到根域名都不同的子应用中实现免登效果。</li><li>慢。每次子应用进入都是一次浏览器上下文重建、资源重新加载的过程。</li></ul><blockquote><p>其中有的问题比较好解决(问题1)，</p><p>有的问题我们可以睁一只眼闭一只眼(问题4)，</p><p>但有的问题我们则很难解决(问题3)甚至无法解决(问题2)，</p><p>而这些无法解决的问题恰恰又会给产品带来非常严重的体验问题， 最终导致我们舍弃了 iframe 方案。</p></blockquote><h2 id="微前端的价值" tabindex="-1"><a class="header-anchor" href="#微前端的价值" aria-hidden="true">#</a> 微前端的价值</h2><ul><li><p><strong>技术栈无关</strong>：主框架不限制接入应用的技术栈，子应用具备完全自主权</p></li><li><p><strong>独立开发、独立部署</strong>：子应用仓库独立，前后端可独立开发，部署完成后主框架自动完成同步更新</p></li><li><p><strong>独立运行</strong>：每个子应用之间状态隔离，运行时状态不共享</p></li></ul><h2 id="qiankun-源码分析" tabindex="-1"><a class="header-anchor" href="#qiankun-源码分析" aria-hidden="true">#</a> qiankun 源码分析</h2>',8),f={href:"https://juejin.cn/post/6844904115999342600",target:"_blank",rel:"noopener noreferrer"},k=(0,i.Uk)("qiankun 源码分析"),g={render:function(e,r){const n=(0,i.up)("OutboundLink");return(0,i.wg)(),(0,i.j4)(i.HY,null,[a,(0,i.Wm)("ul",null,[(0,i.Wm)("li",null,[(0,i.Wm)("a",t,[l,(0,i.Wm)(n)])]),(0,i.Wm)("li",null,[(0,i.Wm)("a",o,[u,(0,i.Wm)(n)])]),(0,i.Wm)("li",null,[(0,i.Wm)("a",h,[s,(0,i.Wm)(n)])])]),m,(0,i.Wm)("p",null,[(0,i.Wm)("a",p,[c,(0,i.Wm)(n)])]),d,(0,i.Wm)("p",null,[(0,i.Wm)("a",f,[k,(0,i.Wm)(n)])])],64)}}}}]);